mapper.select:
SELECT tyt.ID "tallyId", tyt.PLAN_ID, tyt.PROCESS_CODE, tyt.PROCESS_NAME, tyt.TRANSPORT_EQUIPMENT_ID, tyt.TRANSPORT_EQUIPMENT_NO, tyt.WEIGHBRIDGE_ID, tyt.PLAN_NO, tyt.TALLY_STATUS, tyt.DEL_FLAG, tyti.ID TALLY_ITEM_ID, tyti.CARGO_INFO_ID, tyti.CARGO_CODE, tyti.CARGO_NAME, tyti.QUANTITY, wrp.WEIGHT_GOODS TON, tyti.LOCATION_ID, tyti.LOCATION_NO, tyti.STACK_POSITION_NAME, tyti.TRUST_CARGO_INFO_ID, MWP.SOURCE_CD "sourceCd", MWP.SOURCE_NM "sourceNm", MWP.TARGET_CD "targetCd", MWP.TARGET_NM "targetNm", msy3.ID STOREHOUSE_ID, msy3.SHORT_CD STOREHOUSE_NAME, msy2.ID REGION_ID, msy2.SHORT_CD REGION_NAME, msy1.ID MASS_ID, msy1.STORAGE_YARD_NM MASS_NAME, TPWP.CLASS_CODE , TPWP.CLASS_NAME , TPWP.WORK_DATE, tppsd.ID PORT_STORAGE_DETAIL_ID, wrp.WEIGH_IN_DT, wrp.WEIGH_OUT_DT, wrp.UNION_NO, tyti.SOURCE_OR_TARGET_FLAG, tpwp.COMPANY_ID , tpwp.COMPANY_NAME , tbt.TRUST_NO , tpwp.TRUST_ID FROM T_YARD_TALLY tyt LEFT JOIN T_YARD_TALLY_ITEM tyti ON tyt.id = tyti.tally_id INNER JOIN WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND wrp ON tyt.WEIGHBRIDGE_ID = WRP.NOTE_ID LEFT JOIN M_WORK_PROCESS mwp ON MWP.PROCESS_CD = TYT.PROCESS_CODE LEFT JOIN M_STORAGE_YARD msy1 ON tyti.STACK_POSITION_ID = msy1.id LEFT JOIN M_STORAGE_YARD msy2 ON msy1.PARENT_ID = msy2.ID LEFT JOIN M_STORAGE_YARD msy3 ON msy2.PARENT_ID = msy3.ID LEFT JOIN T_PRD_WORK_PLAN tpwp ON TPWP.ID = TYT.PLAN_ID LEFT JOIN T_PRD_PORT_STORAGE_DETAIL tppsd ON tyt.ID = tppsd.CARGO_TALLY_ID LEFT JOIN T_BUS_TRUST tbt ON TPWP.TRUST_ID = TBT.ID
tyt.WEIGHBRIDGE_ID IS NOT NULL AND tyt.REMARK = '车载' AND tyt.DEL_FLAG = '0'
AND tppsd.ID IS NOT NULL
AND tppsd.ID IS NULL
and wrp.UNION_NO like #{unionNoLike}
AND TO_CHAR(wrp.WEIGH_IN_DT,'YYYY-MM-DD hh24:mi:ss') >= #{startDate}
AND TO_CHAR(wrp.WEIGH_OUT_DT,'YYYY-MM-DD hh24:mi:ss') <= #{endDate}
ORDER BY wrp.WEIGH_IN_DT DESC

SELECT tyt.ID "tallyId", tyt.PLAN_ID, tyt.PROCESS_CODE, tyt.PROCESS_NAME, tyt.TRANSPORT_EQUIPMENT_ID, tyt.TRANSPORT_EQUIPMENT_NO, tyt.WEIGHBRIDGE_ID, tyt.PLAN_NO, tyt.TALLY_STATUS, tyt.DEL_FLAG, tyti.ID TALLY_ITEM_ID, tyti.CARGO_INFO_ID, tyti.CARGO_CODE, tyti.CARGO_NAME, tyti.QUANTITY, wrp.WEIGHT_GOODS TON, tyti.LOCATION_ID, tyti.LOCATION_NO, tyti.STACK_POSITION_NAME, tyti.TRUST_CARGO_INFO_ID, MWP.SOURCE_CD "sourceCd", MWP.SOURCE_NM "sourceNm", MWP.TARGET_CD "targetCd", MWP.TARGET_NM "targetNm", msy3.ID STOREHOUSE_ID, msy3.SHORT_CD STOREHOUSE_NAME, msy2.ID REGION_ID, msy2.SHORT_CD REGION_NAME, msy1.ID MASS_ID, msy1.STORAGE_YARD_NM MASS_NAME, TPWP.CLASS_CODE , TPWP.CLASS_NAME , TPWP.WORK_DATE, tppsd.ID PORT_STORAGE_DETAIL_ID, wrp.WEIGH_IN_DT, wrp.WEIGH_OUT_DT, wrp.UNION_NO, tyti.SOURCE_OR_TARGET_FLAG, tpwp.COMPANY_ID , tpwp.COMPANY_NAME , tbt.TRUST_NO , tpwp.TRUST_ID, wrp.TRUCK_PLATE, TBCI.CARGO_INFO_NO FROM WFG_PORTMIS_POUND.WEIGHT_RECORD_POUND wrp INNER JOIN T_YARD_TALLY tyt ON tyt.WEIGHBRIDGE_ID = WRP.NOTE_ID LEFT JOIN T_YARD_TALLY_ITEM tyti ON TYT.id = TYTI.TALLY_ID LEFT JOIN T_PRD_PORT_STORAGE_DETAIL tppsd ON TPPSD.CARGO_TALLY_DETAIL_ID = TYTI.ID LEFT JOIN T_PRD_WORK_PLAN tpwp ON TPWP.id = tyt.PLAN_ID LEFT JOIN T_BUS_TRUST tbt ON TPWP.TRUST_ID = TBT.ID LEFT JOIN M_WORK_PROCESS mwp ON MWP.PROCESS_CD = TYT.PROCESS_CODE LEFT JOIN M_STORAGE_YARD msy1 ON tyti.STACK_POSITION_ID = msy1.id LEFT JOIN M_STORAGE_YARD msy2 ON msy1.PARENT_ID = msy2.ID LEFT JOIN M_STORAGE_YARD msy3 ON msy2.PARENT_ID = msy3.ID LEFT JOIN T_BUS_CARGO_INFO tbci ON tbci.id = tppsd.CARGO_INFO_ID
tyt.WEIGHBRIDGE_ID IS NOT NULL AND tyt.CREATE_TIME >=to_date('2024-10-01 00:00:00','yyyy-MM-dd hh24:mi:ss') AND tyt.REMARK = '车载' AND tyt.DEL_FLAG = '0'
AND tppsd.ID IS NOT NULL
AND tppsd.ID IS NULL
and wrp.UNION_NO like #{unionNoLike}
AND TO_CHAR(tpwp.WORK_DATE,'YYYY-MM-DD hh24:mi:ss') >= #{startDate}
AND TO_CHAR(tpwp.WORK_DATE,'YYYY-MM-DD hh24:mi:ss') <= #{endDate}
AND tyti.CARGO_NAME like #{cargoNameLike}
AND wrp.TRUCK_PLATE like #{truckPlate}
AND TBCI.CARGO_INFO_NO = #{cargoInfoNo}
ORDER BY wrp.WEIGH_IN_DT DESC
